//! P4 scene model — the running picture of the room: objects, kinematics, certified knowledge.
//!
//! Each tick, confirmed tracks are gated by [`crate::physics::admit`]; objects whose net verdict
//! is `Decline` (e.g. superluminal association jumps) are dropped, the rest become [`SceneObject`]s
//! carrying their admitted state. The local certified knowledge set is rebuilt from the accepted
//! facts. This is what P5 publishes as a plenoramic body aeon frame for Thoth.

use crate::affordance::{AffordanceConfig, GraspAffordance, assess_grasp_affordance};
use crate::counterfactual::{CounterfactualConfig, CounterfactualOutcome, apply_impulse_certified};
use crate::interaction::{Interaction, InteractionConfig, InteractionDetector, MomentumSample};
use crate::knowledge::{CertifiedKnowledge, Predicate};
use crate::metacog::{MetacogState, MetacogTracker};
use crate::object_intel::{AbstainReason, IntelConfig, RigidProfile, profile_track_with_prior};
use crate::priors::PriorSet;
use crate::scene_intel::{SceneIntel, SceneIntelTick};
use crate::physics::{AdmittedState, PhysicsConfig, Verdict, admit};
use crate::prediction::{PredictionConfig, Predictor, Validation};
use crate::track::Tracker;

/// Reserved track id for Thoth's own acting hand in the AGENCY predicates (`PossibleGrab(hand, obj)`).
/// It is NOT a tracked body — it is the fixed identity of the agent whose hand could grasp an observed
/// object. Distinct from any real track id (real ids start at 1 and grow; 0 is reserved here).
pub const AGENT_HAND_ID: u64 = 0;

/// One object in the running picture (resolution-independent normalised frame).
#[derive(Clone, Debug)]
pub struct SceneObject {
    pub id: u64,
    pub x: f32,
    pub y: f32,
    pub vx: f32,
    pub vy: f32,
    pub speed: f32,
    pub bw: f32,
    pub bh: f32,
    pub genus: u32,
    /// The object's current in-plane director lift (continuous radians) from its orientation-spinor.
    /// Carried here so the certified-prediction hook can forecast the director forward (and grade it)
    /// without reaching back into the track. Meaningful only when the spinor lift is reliable; the
    /// free_rotation forecast itself gates on `profile.omega` being present.
    pub director_unwrapped: f32,
    /// Certified relative rigid-body dynamical profile (regime + conservation verdicts + ratios).
    /// Present for accepted/abstained objects; carries the at_rest/free_translation/free_rotation/
    /// forced/abstain verdict and the laws each clause passed. See `object_intel`.
    pub profile: RigidProfile,
    /// The object's PERSISTENT IDENTITY FINGERPRINT: the 8x8 luma appearance signature carried by its
    /// track (`track.rs::Track::sig`), EMA-updated as the object is re-matched. This is the REAL
    /// per-object signature (not a derived proxy); it is threaded through here so `publish` can emit a
    /// stable identity descriptor for the downstream knotgraph memory's cross-clip re-identification.
    /// See `publish::identity_json` (the descriptor: luma bands + material axis + size axis + knot key).
    pub luma_sig: [u8; 64],
}

pub struct SceneModel {
    pub round: u64,
    /// Accepted/abstained objects (declined ones are excluded) with their admitted state.
    pub objects: Vec<(SceneObject, AdmittedState)>,
    /// Certified knowledge for THIS tick only (the current view, rebuilt each frame, carve-meet-
    /// mergeable across observers). This is the ephemeral per-tick read.
    pub knowledge: CertifiedKnowledge,
    /// The RUNNING accumulated certified picture — the memory foundation (Phase 3a). Updated each
    /// tick by `accumulate`: facts for observed objects carve-MEET against the per-tick `knowledge`
    /// (a fact survives only while it keeps re-certifying), and facts for objects NOT observed this
    /// tick (occluded / out of frame) CARRY FORWARD untouched ("known until contradicted"). This is
    /// what makes the picture PERSIST across ticks instead of being rebuilt ephemerally. The carve
    /// discipline is the existing `meet` intersection (`SilhouetteCarveLattice.meet_is_semilattice`);
    /// only WHICH predicates participate is scoped by observation. See `crate::knowledge::accumulate`.
    pub accumulated: CertifiedKnowledge,
    /// Objects declined this tick (for honest reporting).
    pub declined: u64,
    /// Certified (or held) multi-object INTERACTIONS detected so far: pairwise collisions certified
    /// by total-momentum conservation and classified elastic/inelastic by total KE. Cross-tick
    /// memory lives in `idet`; this is the cumulative list (newest interactions appended). See
    /// `crate::interaction`.
    pub interactions: Vec<Interaction>,
    /// SCENE-LEVEL relational read for the latest tick: object/moving counts, non-rigid/actuated
    /// objects, and detected grab/manipulation relations. Robust to every object's regime abstaining
    /// (it reads structure from proximity + co-motion, not conservation). See `crate::scene_intel`.
    pub scene_intel: SceneIntelTick,
    /// All grab/manipulation relations EVER detected over the clip (cumulative, deduplicated by pair
    /// while the contact persists), for a clip-level summary even if the final tick is mid-occlusion.
    pub grab_relations: Vec<crate::scene_intel::Relation>,
    /// CERTIFIED AGENCY (Phase 2) for the latest tick: per accepted/abstained object, the manual
    /// affordance (graspable / pushable / droppable — or an honest abstain/decline) derived from its
    /// certified profile by `crate::affordance`. The C2-shadow gate made prescriptive: Thoth only acts
    /// on a clean abstain_reason. Rebuilt each tick (the prescriptive read of the current picture).
    pub affordances: Vec<GraspAffordance>,
    /// CERTIFIED COUNTERFACTUAL (Phase 2) for the latest tick: for each ADMISSIBLE (accepted) grasp
    /// affordance, a sample certified outcome — "IF Thoth applies a canceling impulse to arrest the
    /// body, the post-impulse velocity is v', the hypothetical collision is momentum-conserved" —
    /// derived by `crate::counterfactual` (NO force solver). Rebuilt each tick.
    pub counterfactuals: Vec<CounterfactualOutcome>,
    pcfg: PhysicsConfig,
    icfg: IntelConfig,
    /// Manual-affordance gate config (hand reach + impulse budget, relative). See `crate::affordance`.
    afcfg: AffordanceConfig,
    /// Counterfactual-rollout config (momentum tol + regime hold floor). See `crate::counterfactual`.
    cfcfg: CounterfactualConfig,
    /// Per-track recon MATERIAL/MASS/INERTIA priors (the recon -> third-eye feedback). When a track id
    /// has a prior, its object profile is GROUNDED: mass = material_density × volume (material-weighted
    /// inter-object ratio) instead of the relative `DENSITY_GUESS = 1.0`. Empty by default (relative
    /// equal-density). See `crate::priors` and `crate::object_intel::ObjectPrior`.
    priors: PriorSet,
    /// Cross-tick interaction detector (rolling per-object momentum history).
    idet: InteractionDetector,
    /// Cross-tick scene-level relational detector (rolling per-pair contact + co-motion).
    sidet: SceneIntel,
    /// Certified-prediction engine: issues conditional, regime-gated forecasts and self-validates
    /// them against the realised state once the clip advances. See `crate::prediction`.
    predictor: Predictor,
    /// The C0-C3 metacognitive gate state for the latest tick (the runtime mirror of
    /// `NeurosymbolicToolUseMarkov`). `None` before the first `update`. See `crate::metacog`.
    metacog: Option<MetacogState>,
    /// Cross-tick metacognitive accumulator (prev score, plateau counter, carried shadow). Folds the
    /// C0-C3 walk across ticks so shadow is carried forward, never silently dropped.
    metacog_tracker: MetacogTracker,
}

impl SceneModel {
    pub fn new(pcfg: PhysicsConfig) -> Self {
        let icfg = IntelConfig::default();
        SceneModel {
            round: 0,
            objects: Vec::new(),
            knowledge: CertifiedKnowledge::new(),
            accumulated: CertifiedKnowledge::new(),
            declined: 0,
            interactions: Vec::new(),
            scene_intel: SceneIntelTick::default(),
            grab_relations: Vec::new(),
            affordances: Vec::new(),
            counterfactuals: Vec::new(),
            pcfg,
            icfg,
            afcfg: AffordanceConfig::default(),
            cfcfg: CounterfactualConfig::default(),
            priors: PriorSet::default(),
            idet: InteractionDetector::new(),
            sidet: SceneIntel::new(),
            predictor: Predictor::new(),
            metacog: None,
            metacog_tracker: MetacogTracker::new(),
        }
    }

    /// Install the recon MATERIAL/MASS/INERTIA priors (the recon -> third-eye feedback). With priors,
    /// each matched track's object profile is GROUNDED — mass = material_density × volume, so a small
    /// dense object and a big light one are weighed by their REAL material ratio (not equal density),
    /// and the interaction detector certifies momentum conservation with those material-weighted
    /// masses. If ANY prior carries an absolute scale reference, the detector may report absolute SI;
    /// otherwise absolute SI is abstained and only the material-grounded RATIO is certified. Call
    /// before the first `update`.
    pub fn set_priors(&mut self, priors: PriorSet) {
        let mut icfg = InteractionConfig::default();
        icfg.si_scale_ref = priors.has_scale_ref();
        self.idet = InteractionDetector::with_config(icfg);
        self.priors = priors;
    }

    /// Override the manual-affordance gate config (hand reach + impulse budget, both RELATIVE — same
    /// units as the profile's char_size / momentum). `None` keeps the default for that field. Tunes
    /// what counts as "too big to grasp" / "too much momentum to arrest" without disturbing the rest.
    pub fn set_affordance_config(&mut self, hand_reach: Option<f32>, max_impulse: Option<f32>) {
        if let Some(r) = hand_reach {
            self.afcfg.hand_reach = r;
        }
        if let Some(j) = max_impulse {
            self.afcfg.max_impulse = j;
        }
    }

    /// Override the certified-prediction config (e.g. a custom horizon). Must be called before the
    /// first `update` to take effect cleanly (it resets the predictor's per-object state).
    pub fn set_prediction_config(&mut self, cfg: PredictionConfig) {
        self.predictor = Predictor::with_config(cfg);
    }

    /// Override the metacognitive plateau window (consecutive flat-E8-score ticks, with shadow
    /// persisting, before C3 flags a plateau loop). Must be called before the first `update`.
    pub fn set_metacog_plateau_window(&mut self, window: u32) {
        self.metacog_tracker = MetacogTracker::with_plateau_window(window);
    }

    /// Rebuild the picture from the tracker's confirmed tracks.
    pub fn update(&mut self, tracker: &Tracker) {
        self.round += 1;
        let mut objs = Vec::new();
        let mut declined = 0u64;
        // Per-tick momentum samples (vector p = m*v) for the cross-tick interaction detector.
        let mut samples: Vec<MomentumSample> = Vec::new();
        for t in tracker.confirmed() {
            let adm = admit(t, &self.pcfg);
            if adm.verdict == Verdict::Decline {
                declined += 1;
                continue;
            }
            // GROUND the per-object physics with the recon material prior keyed by track id (the
            // recon -> third-eye feedback). With a prior, mass = material_density × volume; without,
            // the relative equal-density fallback. p = m·v and L = I·ω below then use the material-
            // weighted mass/inertia, so the interaction detector weighs the pair by their real ratio.
            let prior = self.priors.get(t.id);
            let profile = profile_track_with_prior(t, self.pcfg.c_max, &self.icfg, prior);
            // Capture this object's momentum VECTOR (the per-object regime already tells us when its
            // own momentum changed; the detector folds two such `forced` events into a collision).
            samples.push(MomentumSample {
                id: t.id,
                round: self.round,
                pts: t.last_pts,
                mass: profile.mass,
                x: t.x(), // centroid (filtered position)
                y: t.y(),
                size: profile.char_size,
                px: profile.mass * profile.vx,
                py: profile.mass * profile.vy,
                ke: profile.ke_lin,
                regime: profile.regime,
                confidence: adm.confidence,
                material: profile.material,
                grounded: profile.grounded,
            });
            let obj = SceneObject {
                id: t.id,
                x: t.x(),
                y: t.y(),
                vx: t.vx(),
                vy: t.vy(),
                speed: t.speed(),
                bw: t.bw,
                bh: t.bh,
                genus: t.genus,
                director_unwrapped: t.spinor.director_unwrapped,
                profile,
                // REAL per-object identity fingerprint: the track's EMA-updated 8x8 luma signature.
                // Threaded verbatim (no derivation) so `publish` emits Thoth's true cross-clip re-id key.
                luma_sig: t.sig,
            };
            objs.push((obj, adm));
        }
        self.knowledge = CertifiedKnowledge::from_scene(&objs);

        // CERTIFIED AGENCY (Phase 2): derive what Thoth can DO from what the picture PROVES. For each
        // accepted/abstained object, gate its certified profile into a manual affordance (graspable /
        // pushable / droppable — or an honest abstain/decline). The C2-shadow gate made prescriptive:
        // a NonRigidActuated / AliasedUnreliable abstain_reason ABSTAINS acting. For each ADMISSIBLE
        // grasp, a sample COUNTERFACTUAL (a canceling impulse that would arrest the body) is certified
        // by the conservation + lightcone laws. NO force solver — both reuse the green laws.
        self.compute_agency(&objs);

        // EMIT the admissible agency facts into THIS tick's certified knowledge so they ACCUMULATE +
        // publish alongside the perceptual predicates (scoped, via Predicate::obj_id, to the object —
        // a PossibleGrab survives only while that object keeps re-certifying as graspable). Thoth's hand
        // id is a fixed reserved id (0 = the agent's own hand) — these are HYPOTHETICAL affordances on
        // observed objects, not a second tracked body.
        for a in &self.affordances {
            if a.admissible() && a.kind == crate::affordance::AffordanceKind::Graspable {
                self.knowledge.add_public(
                    Predicate::PossibleGrab(AGENT_HAND_ID, a.id),
                    crate::affordance::GRASP_LAW,
                );
            }
        }
        for c in &self.counterfactuals {
            if c.certified() {
                self.knowledge.add_public(
                    Predicate::CertifiedOutcome(
                        c.id,
                        CertifiedKnowledge::quantize_velocity(c.v_after_x),
                        CertifiedKnowledge::quantize_velocity(c.v_after_y),
                    ),
                    crate::counterfactual::OUTCOME_LAW,
                );
            }
        }

        // RUNNING-PICTURE ACCUMULATION (Phase 3a, the memory foundation): fold this tick's certified
        // `knowledge` into the persistent `accumulated` set, scoped by which objects were observed.
        // The objects observed this tick are exactly those that became `SceneObject`s (admitted, not
        // declined); their facts carve-MEET into the running set (survive only while re-certifying),
        // and unobserved objects' facts carry forward untouched. See `accumulate`.
        let observed_ids: std::collections::BTreeSet<u64> = objs.iter().map(|(o, _)| o.id).collect();
        self.accumulate(&observed_ids);

        // This tick's presentation time = the latest matched observation time across the picture.
        // (The predictor uses it for the horizon and to decide when a forecast's target is reached.)
        let tick_pts = samples.iter().map(|s| s.pts).fold(0.0f64, f64::max);

        // Certified-prediction pass: issue/expire/grade conditional forecasts for this tick's
        // objects. The predictor reads the certified profile (regime + v + ω) and the carried
        // director lift; it issues NO forecast for forced/abstain objects (honest abstain) and
        // expires a free-motion forecast the moment the object is on a collision course.
        self.predictor.observe(tick_pts, &predict_inputs(&objs));

        self.objects = objs;
        self.declined = declined;

        // Cross-tick interaction pass: feed this tick's momentum samples; the detector folds
        // simultaneous forced+approaching pairs into certified/declined/abstained collisions.
        let newly = self.idet.observe(self.round, &samples);
        self.interactions.extend(newly);

        // Cross-tick SCENE-LEVEL relational pass: the structural read that stays useful when every
        // object's rigid regime abstains (a hand grabbing a controller). Reads number moving + grab
        // relations (sustained contact + co-motion) from proximity/velocity, not conservation.
        let reasons: std::collections::HashMap<u64, AbstainReason> = self
            .objects
            .iter()
            .map(|(o, _)| (o.id, o.profile.abstain_reason))
            .collect();
        self.scene_intel = self.sidet.observe(self.round, tick_pts, &samples, &reasons);
        // Accumulate grab relations, keeping the longest-contact instance per pair (most evidence)
        // so the clip-level summary reports each manipulation once with its peak sustained-contact.
        for r in &self.scene_intel.relations {
            if let Some(slot) = self
                .grab_relations
                .iter_mut()
                .find(|g| g.a_id == r.a_id && g.b_id == r.b_id)
            {
                if r.contact_frames > slot.contact_frames {
                    *slot = r.clone();
                }
            } else {
                self.grab_relations.push(r.clone());
            }
        }

        // C0-C3 METACOGNITIVE GATE (the keystone): run the per-tick metacognitive discipline over the
        // freshly-built picture (objects, knowledge, scene-intel, validations, interactions) and fold
        // the cross-tick accumulator. The tracker ENFORCES the discipline `debug_assert!(disciplined)`
        // — the runtime mirror of `no_gain_disciplined_step_exposes_shadow`. See `crate::metacog`.
        // (Take the tracker out so `observe` can borrow `&self` immutably, then put it back — the
        // tracker carries no reference into the scene, so the swap is sound and allocation-free.)
        let mut tracker = std::mem::take(&mut self.metacog_tracker);
        let state = tracker.observe(self);
        self.metacog_tracker = tracker;
        self.metacog = Some(state);
    }

    /// Fold this tick's certified `knowledge` into the running `accumulated` picture (Phase 3a). The
    /// accumulation is SCOPED by `observed_ids` (the objects admitted this tick): their facts carve-
    /// MEET against the per-tick `knowledge` (a fact survives only while it keeps re-certifying —
    /// conservative, anti-flicker, idempotent under re-observation), while facts for objects NOT in
    /// `observed_ids` (occluded / out of frame) CARRY FORWARD untouched ("known until contradicted",
    /// never silently deleted). The carve discipline is the existing `meet` intersection
    /// (`SilhouetteCarveLattice.meet_is_semilattice`); only WHICH predicates participate is scoped.
    ///
    /// SEAM (Phase 3b, do NOT build now): cross-clip re-identification will key persistent object
    /// identity here — `observed_ids` and the predicate object ids assume STABLE ids across ticks; a
    /// re-id layer would remap a re-acquired object's track id onto its persistent identity before
    /// accumulation, so a carried-forward fact rejoins the same identity rather than a fresh one.
    ///
    /// TIE TO METACOG C2: a carried-forward fact is honest PERMANENCE, not a guarantee. When a
    /// remembered object is re-observed but its fact no longer re-certifies, the carve-meet drops it
    /// here — the object falls to abstain on that fact, exposed as C2 shadow, never silently deleted.
    pub fn accumulate(&mut self, observed_ids: &std::collections::BTreeSet<u64>) {
        let this_tick = self.knowledge.clone();
        self.accumulated.accumulate(&this_tick, observed_ids);
    }

    /// CERTIFIED AGENCY (Phase 2): rebuild this tick's affordances + sample counterfactuals from the
    /// accepted/abstained objects' certified profiles. For each object the affordance gate
    /// (`assess_grasp_affordance`) derives the admissible manual action (graspable / pushable /
    /// droppable, or an honest abstain/decline) — the C2-shadow gate made prescriptive. For each
    /// ADMISSIBLE grasp, a sample counterfactual rolls out a CANCELING impulse (J = -p, which arrests
    /// the body) and certifies the outcome by the conservation + lightcone laws (`apply_impulse_certified`).
    /// NO force solver — the impulse is the conserved momentum to arrest, the outcome is its forward image.
    fn compute_agency(&mut self, objs: &[(SceneObject, AdmittedState)]) {
        self.affordances.clear();
        self.counterfactuals.clear();
        for (obj, _adm) in objs {
            let aff = assess_grasp_affordance(&obj.profile, self.afcfg.hand_reach, &self.afcfg);
            // For an ADMISSIBLE grasp, sample the counterfactual of arresting the body: the canceling
            // impulse J = -p brings it to rest (the grasp's job). hold accrued >= hold_min so the
            // regime-after re-certifies (AtRest) rather than abstaining — a single-shot "what if I grab
            // it" rollout. The post-velocity is ~0, trivially subluminal, and the hypothetical absorber
            // collision conserves momentum.
            if aff.admissible()
                && aff.kind == crate::affordance::AffordanceKind::Graspable
            {
                let jx = -obj.profile.mass * obj.profile.vx;
                let jy = -obj.profile.mass * obj.profile.vy;
                let cf = apply_impulse_certified(
                    &obj.profile,
                    jx,
                    jy,
                    None,
                    self.cfcfg.hold_min, // assume the free continuation establishes (single-shot rollout)
                    self.pcfg.c_max,
                    &self.cfcfg,
                );
                self.counterfactuals.push(cf);
            }
            self.affordances.push(aff);
        }
    }

    /// The certified manual affordances for the latest tick (graspable / pushable / droppable, or
    /// honest abstain/decline) — what Thoth can DO, derived from what the picture PROVES. The aeon-3d
    /// worldsim acting surface consumes these as grab/push/move primitives. See `crate::affordance`.
    pub fn affordances(&self) -> &[GraspAffordance] {
        &self.affordances
    }

    /// The certified counterfactual outcomes for the latest tick (one per admissible grasp: the
    /// certified result of arresting the body) — "IF Thoth acts, certified outcome v', momentum-
    /// conserved, unless another force acts". See `crate::counterfactual`.
    pub fn counterfactuals(&self) -> &[CounterfactualOutcome] {
        &self.counterfactuals
    }

    /// The running accumulated certified picture — the memory foundation (Phase 3a). Facts persist
    /// across ticks: observed objects' facts carve-meet (survive only while re-certifying), unobserved
    /// objects' facts carry forward ("known until contradicted"). Distinct from the per-tick
    /// `knowledge` (current view), which is rebuilt each frame and loses an object the moment it is
    /// occluded. See `accumulate`.
    pub fn accumulated_knowledge(&self) -> &CertifiedKnowledge {
        &self.accumulated
    }

    /// The latest tick's C0-C3 metacognitive gate state (the runtime mirror of
    /// `NeurosymbolicToolUseMarkov`), or `None` before the first `update`. See `crate::metacog`.
    pub fn metacog(&self) -> Option<&MetacogState> {
        self.metacog.as_ref()
    }

    /// The certified-prediction engine (issued forecasts + self-validations). See `crate::prediction`.
    pub fn predictor(&self) -> &Predictor {
        &self.predictor
    }

    /// Completed self-validations so far (forecasts graded against the realised state).
    pub fn validations(&self) -> &[Validation] {
        &self.predictor.validations
    }

    /// The accepted/abstained objects with their admitted state. (Declined ones are excluded.)
    pub fn objects(&self) -> &[(SceneObject, AdmittedState)] {
        &self.objects
    }

    /// Multi-object interactions detected so far (certified collisions, declined non-isolated pairs,
    /// and abstained tracking-limited events). See `crate::interaction`.
    pub fn interactions(&self) -> &[Interaction] {
        &self.interactions
    }

    /// The latest tick's scene-level relational read (counts + non-rigid objects + grab relations).
    pub fn scene_intel(&self) -> &SceneIntelTick {
        &self.scene_intel
    }

    /// All grab/manipulation relations detected over the clip (one per pair, peak sustained-contact).
    pub fn grab_relations(&self) -> &[crate::scene_intel::Relation] {
        &self.grab_relations
    }

    /// Count of objects whose net verdict is `Accept` (fully certified as real & known).
    pub fn accepted(&self) -> usize {
        self.objects
            .iter()
            .filter(|(_, a)| a.verdict == Verdict::Accept)
            .count()
    }

    /// Count abstained (present but not yet provably known).
    pub fn abstained(&self) -> usize {
        self.objects
            .iter()
            .filter(|(_, a)| a.verdict == Verdict::Abstain)
            .count()
    }

    // ── test hooks (cfg(test) only) ──────────────────────────────────────────
    // The metacog gate reads `objects`, `knowledge`, `scene_intel`, `validations`, and `interactions`.
    // These hooks let the metacog unit tests build a deterministic picture WITHOUT a full decode/track
    // pass; they are NOT compiled into the production binary and disturb no production field.

    /// Install a hand-built object set and rebuild the certified knowledge from it (mirrors the
    /// production `update` knowledge step). Bumps `round` so the metacog tracker sees a fresh tick.
    #[cfg(test)]
    pub fn set_objects_for_test(&mut self, objs: Vec<(SceneObject, AdmittedState)>) {
        self.round += 1;
        self.knowledge = CertifiedKnowledge::from_scene(&objs);
        self.compute_agency(&objs);
        let observed_ids: std::collections::BTreeSet<u64> = objs.iter().map(|(o, _)| o.id).collect();
        self.accumulate(&observed_ids);
        self.objects = objs;
    }

    /// Push a completed self-validation into the predictor (so the metacog C3 regression check can see
    /// a `Decline` grade) without running the predictor end-to-end.
    #[cfg(test)]
    pub fn push_validation_for_test(&mut self, v: Validation) {
        self.predictor.validations.push(v);
    }

    /// Push a detected interaction (so the metacog C3 bias check can see a grounded certified
    /// collision) without running the interaction detector.
    #[cfg(test)]
    pub fn push_interaction_for_test(&mut self, it: Interaction) {
        self.interactions.push(it);
    }
}

/// Project the admitted picture to the (object, net-verdict) pairs the predictor consumes. The
/// predictor needs only the object's certified state and whether it was admitted; it does not read
/// the full physics admission, so we hand it the net verdict.
fn predict_inputs(objs: &[(SceneObject, AdmittedState)]) -> Vec<(SceneObject, Verdict)> {
    objs.iter().map(|(o, a)| (o.clone(), a.verdict)).collect()
}
